BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?child ?propName ?defaultValue WHERE {
  ?elem vocab:NamedElement_name "Peak%20Power%20Limit%20Requirement%20JPL" .
  ?elem vocab:Element_ownedElement ?child .
  ?child vocab:NamedElement_name ?propName .
  OPTIONAL { ?child vocab:Property_defaultValue ?defaultValue }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?vp ?vpName ?spec ?default WHERE {
  ?elem vocab:NamedElement_name "Peak%20Power%20Limit%20Requirement%20JPL" .
  ?elem vocab:Element_ownedElement ?vp .
  ?vp rdf:type vocab:value%20property .
  ?vp vocab:NamedElement_name ?vpName .
  OPTIONAL { ?vp vocab:Property_defaultValue ?dv . ?dv vocab:ValueSpecification_expression ?spec }
  OPTIONAL { ?vp vocab:Property_defaultValue ?default }
}
LIMIT 50

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?vp ?vpName ?default WHERE {
  ?vp vocab:NamedElement_name ?vpName .
  FILTER(CONTAINS(?vpName, "powerPeakLimit"))
  OPTIONAL { ?vp vocab:Property_defaultValue ?default }
}
LIMIT 20

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?vpName ?value ?spec WHERE {
  ?block vocab:NamedElement_name "Peak%20Power%20Limit%20Requirement%20TMT" .
  ?block vocab:Element_ownedElement ?vp .
  ?vp rdf:type <http://api.koneksys.com/cameo/vocab/value%20property> .
  ?vp vocab:NamedElement_name ?vpName .
  OPTIONAL { ?vp vocab:Property_defaultValue ?default . 
             { ?default vocab:LiteralString_value ?value } 
             UNION { ?default vocab:LiteralReal_value ?value }
             UNION { ?default vocab:ValueSpecification_expression ?value } }
}
LIMIT 30

