  OPTIONAL { ?vp vocab:Property_defaultValue ?default . 
             { ?default vocab:LiteralString_value ?value } 
             UNION { ?default vocab:LiteralReal_value ?value }
             UNION { ?default vocab:ValueSpecification_expression ?value } }
