LIMIT 30

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?cpName ?spec ?expr WHERE {
  ?block vocab:NamedElement_name "Peak%20Power%20Limit%20Requirement%20JPL" .
  ?block vocab:Element_ownedElement ?cp .
  ?cp vocab:NamedElement_name ?cpName .
  OPTIONAL { ?cp vocab:Constraint_specification ?spec }
  OPTIONAL { ?spec vocab:ValueSpecification_expression ?expr }
}
LIMIT 30
